const items = $input.all();
const K = [
  0x428a2f98, 0x71374491, 0xb5c0fbcf, 0xe9b5dba5, 0x3956c25b, 0x59f111f1, 0x923f82a4, 0xab1c5ed5,
  0xd807aa98, 0x12835b01, 0x243185be, 0x550c7dc3, 0x72be5d74, 0x80deb1fe, 0x9bdc06a7, 0xc19bf174,
  0xe49b69c1, 0xefbe4786, 0x0fc19dc6, 0x240ca1cc, 0x2de92c6f, 0x4a7484aa, 0x5cb0a9dc, 0x76f988da,
  0x983e5152, 0xa831c66d, 0xb00327c8, 0xbf597fc7, 0xc6e00bf3, 0xd5a79147, 0x06ca6351, 0x14292967,
  0x27b70a85, 0x2e1b2138, 0x4d2c6dfc, 0x53380d13, 0x650a7354, 0x766a0abb, 0x81c2c92e, 0x92722c85,
  0xa2bfe8a1, 0xa81a664b, 0xc24b8b70, 0xc76c51a3, 0xd192e819, 0xd6990624, 0xf40e3585, 0x106aa070,
  0x19a4c116, 0x1e376c08, 0x2748774c, 0x34b0bcb5, 0x391c0cb3, 0x4ed8aa4a, 0x5b9cca4f, 0x682e6ff3,
  0x748f82ee, 0x78a5636f, 0x84c87814, 0x8cc70208, 0x90befffa, 0xa4506ceb, 0xbef9a3f7, 0xc67178f2,
];

function rotr(value, bits) {
  return (value >>> bits) | (value << (32 - bits));
}

function pureSha256Hex(buffer) {
  const bytes = new Uint8Array(buffer);
  const bitLength = bytes.length * 8;
  const paddedLength = Math.ceil((bytes.length + 1 + 8) / 64) * 64;
  const padded = new Uint8Array(paddedLength);
  padded.set(bytes);
  padded[bytes.length] = 0x80;

  const view = new DataView(padded.buffer);
  view.setUint32(paddedLength - 8, Math.floor(bitLength / 0x100000000));
  view.setUint32(paddedLength - 4, bitLength >>> 0);

  let h0 = 0x6a09e667;
  let h1 = 0xbb67ae85;
  let h2 = 0x3c6ef372;
  let h3 = 0xa54ff53a;
  let h4 = 0x510e527f;
  let h5 = 0x9b05688c;
  let h6 = 0x1f83d9ab;
  let h7 = 0x5be0cd19;
  const w = new Uint32Array(64);

  for (let offset = 0; offset < paddedLength; offset += 64) {
    for (let i = 0; i < 16; i += 1) {
      w[i] = view.getUint32(offset + i * 4);
    }
    for (let i = 16; i < 64; i += 1) {
      const s0 = rotr(w[i - 15], 7) ^ rotr(w[i - 15], 18) ^ (w[i - 15] >>> 3);
      const s1 = rotr(w[i - 2], 17) ^ rotr(w[i - 2], 19) ^ (w[i - 2] >>> 10);
      w[i] = (w[i - 16] + s0 + w[i - 7] + s1) >>> 0;
    }

    let a = h0;
    let b = h1;
    let c = h2;
    let d = h3;
    let e = h4;
    let f = h5;
    let g = h6;
    let h = h7;

    for (let i = 0; i < 64; i += 1) {
      const S1 = rotr(e, 6) ^ rotr(e, 11) ^ rotr(e, 25);
      const ch = (e & f) ^ (~e & g);
      const temp1 = (h + S1 + ch + K[i] + w[i]) >>> 0;
      const S0 = rotr(a, 2) ^ rotr(a, 13) ^ rotr(a, 22);
      const maj = (a & b) ^ (a & c) ^ (b & c);
      const temp2 = (S0 + maj) >>> 0;
      h = g;
      g = f;
      f = e;
      e = (d + temp1) >>> 0;
      d = c;
      c = b;
      b = a;
      a = (temp1 + temp2) >>> 0;
    }

    h0 = (h0 + a) >>> 0;
    h1 = (h1 + b) >>> 0;
    h2 = (h2 + c) >>> 0;
    h3 = (h3 + d) >>> 0;
    h4 = (h4 + e) >>> 0;
    h5 = (h5 + f) >>> 0;
    h6 = (h6 + g) >>> 0;
    h7 = (h7 + h) >>> 0;
  }

  return [h0, h1, h2, h3, h4, h5, h6, h7]
    .map((value) => value.toString(16).padStart(8, '0'))
    .join('');
}

async function sha256Hex(buffer) {
  const bytes = new Uint8Array(buffer);
  if (globalThis.crypto?.subtle) {
    const digest = await globalThis.crypto.subtle.digest('SHA-256', bytes);
    return Array.from(new Uint8Array(digest)).map((byte) => byte.toString(16).padStart(2, '0')).join('');
  }

  return pureSha256Hex(bytes);
}

return await Promise.all(items.map(async (item, index) => {
  const binaryKeys = Object.keys(item.binary || {});
  const binaryPropertyName = item.binary?.data ? 'data' : binaryKeys[0];

  if (!binaryPropertyName) {
    throw new Error('Downloaded KB file is missing binary data for content hashing');
  }

  const buffer = await this.helpers.getBinaryDataBuffer(index, binaryPropertyName);
  const contentSha256 = await sha256Hex(buffer);

  return {
    json: {
      ...item.json,
      content_sha256: contentSha256,
    },
    binary: item.binary,
  };
}));

const insertedItems = $input.all();
let sourceItems;
try {
  sourceItems = $items('Restore Pinecone Ingestion Context');
} catch (error) {
  sourceItems = insertedItems;
}

function text(value) {
  return String(value ?? '').trim();
}

function workflowTimestamp() {
  try {
    const formatter = new Intl.DateTimeFormat('sv-SE', {
      timeZone: '__SET_WORKFLOW_TIMEZONE__',
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
      hour12: false,
    });
    return formatter.format(new Date()).replace(',', '') + ' __SET_WORKFLOW_TIMEZONE_LABEL__';
  } catch (error) {
    return new Date().toISOString();
  }
}

function chunkCount(source, inserted) {
  const explicit = Number(source.chunks_count ?? source.chunk_count ?? inserted.chunks_count ?? inserted.chunk_count ?? 0);
  if (Number.isFinite(explicit) && explicit > 0) return explicit;
  if (Array.isArray(source.chunks)) return source.chunks.length;
  if (Array.isArray(inserted.chunks)) return inserted.chunks.length;
  if (Array.isArray(inserted.documents)) return inserted.documents.length;
  return 1;
}

return sourceItems.map((item, index) => {
  const source = item.json || {};
  const inserted = insertedItems[index]?.json || {};
  const fileId = text(source.source_file_id || source.file_id || source.id || source.fileId);
  const namespace = text(source.namespace) || '__SET_PREPARE_CHUNK_METADATA_NAMESPACE__';
  const contentSha256 = text(source.content_sha256 || inserted.content_sha256);
  const ingestionKey = text(source.ingestion_key) || [fileId || 'unknown_file_id', contentSha256 || 'unknown_content_sha256', namespace].join('::');

  return {
    json: {
      file_id: fileId,
      file_name: text(source.source_file_name || source.file_name || source.name || source.fileName),
      file_url: text(source.google_drive_url || source.file_url || source.webViewLink),
      event_type: text(source.event_type || inserted.event_type || 'indexed'),
      status: 'completed',
      chunks_count: chunkCount(source, inserted),
      namespace,
      execution_id: text(source.execution_id || inserted.execution_id || $execution.id),
      ingested_at: text(source.ingested_at) || workflowTimestamp(),
      error_message: '',
      ingestion_key: ingestionKey,
      modified_time: text(source.modified_time || source.modifiedTime || inserted.modified_time),
      content_sha256: contentSha256,
    },
  };
});

const seen = new Set();
const output = [];

for (const item of $input.all()) {
  const json = item.json || {};
  const fileId = String(json.id || json.fileId || '').trim();
  const fileName = String(json.name || json.fileName || '').trim().toLowerCase();
  const key = fileId || fileName;

  if (key && seen.has(key)) continue;
  if (key) seen.add(key);

  output.push(item);
}

return output;

const responses = $input.all();
let sourceItems;
try {
  sourceItems = $items('Select Changed KB File');
} catch (error) {
  sourceItems = responses;
}

function text(value) {
  return String(value ?? '').trim();
}

function pineconeHost(response) {
  const json = response.json || {};
  const candidates = [
    json.host,
    json.index?.host,
    json.data?.host,
    json.result?.host,
    json.body?.host,
  ];
  const host = candidates.map(text).find(Boolean);
  if (!host) throw new Error('Pinecone index host response is missing host');
  return host.replace(/^https?:\/\//i, '').replace(/\/+$/, '');
}

return responses.map((response, index) => {
  const sourceItem = sourceItems[index] || response;
  const source = sourceItem.json || {};
  const namespace = text(source.namespace) || '__SET_PREPARE_CHUNK_METADATA_NAMESPACE__';
  const fileId = text(source.source_file_id || source.file_id || source.id || source.fileId);

  if (!fileId) {
    throw new Error('Cannot prepare Pinecone delete request without a stable source file id');
  }

  return {
    json: {
      ...source,
      pinecone_delete_url: 'https://' + pineconeHost(response) + '/vectors/delete',
      pinecone_delete_body: {
        namespace,
        filter: {
          source_file_id: {
            '$eq': fileId,
          },
        },
      },
    },
    binary: sourceItem.binary,
  };
});

const deleteResults = $input.all();
const sourceItems = $items('Prepare Pinecone Delete Request');

function pineconeErrorText(error = {}) {
  return [
    error.description,
    error.message,
    error.response?.body?.description,
    error.response?.body?.message,
    error.response?.body?.error?.description,
    error.response?.body?.error?.message,
  ].filter(Boolean).join(' ');
}

function responseStatus(result) {
  const error = result.error || {};
  const statusCode = Number(result.statusCode || result.status || error.statusCode || error.status || error.httpCode || error.response?.statusCode || error.response?.status || 0);
  if (statusCode) return statusCode;
  if (/Namespace not found/i.test(pineconeErrorText(error))) return 404;
  return result.error ? 500 : 200;
}

function responseBody(result) {
  if (result.body !== undefined) return result.body;
  if (result.error?.response?.body !== undefined) return result.error.response.body;
  if (result.error?.message || result.error?.description) return { message: result.error.message, description: result.error.description };
  return result;
}

for (let index = 0; index < deleteResults.length; index += 1) {
  const result = deleteResults[index].json || {};
  const statusCode = responseStatus(result);
  const body = responseBody(result);
  const bodyText = typeof body === 'string' ? body : JSON.stringify(body);
  const message = typeof body === 'object' && body !== null ? String([body.message, body.description, body.error?.message, body.error?.description].filter(Boolean).join(' ')) : bodyText;
  const isSuccess = statusCode >= 200 && statusCode < 300;
  const isFirstRunMissingNamespace = statusCode === 404 && /Namespace not found/i.test(message || bodyText);

  if (!isSuccess && !isFirstRunMissingNamespace) {
    const source = sourceItems[index]?.json || {};
    const fileRef = source.source_file_id || source.source_file_name || `item ${index + 1}`;
    throw new Error(`Pinecone delete failed for ${fileRef} (${statusCode}): ${bodyText}`);
  }
}

return sourceItems.map((item) => ({
  json: item.json,
  binary: item.binary
}));

const PINECONE_KB_NAMESPACE = '__SET_PREPARE_CHUNK_METADATA_NAMESPACE__';
const sourceItems = $items('Prepare Chunk Metadata');
const currentStateRows = $input.all().map((item) => item.json || {});

function clean(value) {
  return String(value ?? '').trim();
}

function stableFileId(source) {
  const fileId = clean(source.source_file_id);
  return fileId && !fileId.startsWith('unknown_file_') ? fileId : '';
}

function matchesCurrentState(row, source) {
  const rowFileId = clean(row.file_id || row.source_file_id);
  const rowNamespace = clean(row.namespace) || PINECONE_KB_NAMESPACE;
  const sourceFileId = stableFileId(source);
  const sourceNamespace = clean(source.namespace) || PINECONE_KB_NAMESPACE;

  return Boolean(sourceFileId) && rowFileId === sourceFileId && rowNamespace === sourceNamespace;
}

function currentStateAllowsSkip(row, source) {
  const status = clean(row.status).toLowerCase();
  const rowIngestionKey = clean(row.current_ingestion_key);
  const sourceIngestionKey = clean(source.ingestion_key);

  return status === 'completed' && Boolean(rowIngestionKey) && rowIngestionKey === sourceIngestionKey;
}

function changedStatus(rows, source) {
  if (rows.length === 0) return 'missing_current_state';
  if (rows.length > 1) return 'ambiguous_current_state';
  if (currentStateAllowsSkip(rows[0], source)) return 'unchanged_current_state';
  return 'changed_current_state';
}

const changedItems = [];

for (const sourceItem of sourceItems) {
  const source = sourceItem.json || {};
  const fileId = stableFileId(source);
  const ingestionKey = clean(source.ingestion_key);

  if (!fileId || !ingestionKey) {
    changedItems.push({
      json: {
        ...source,
        dedupe_lookup_status: 'missing_stable_key',
      },
      binary: sourceItem.binary,
    });
    continue;
  }

  const matchingRows = currentStateRows.filter((row) => matchesCurrentState(row, source));
  const status = changedStatus(matchingRows, source);

  if (status === 'unchanged_current_state') {
    continue;
  }

  changedItems.push({
    json: {
      ...source,
      dedupe_lookup_status: status,
      previous_current_content_sha256: clean(matchingRows[0]?.current_content_sha256),
      previous_current_ingestion_key: clean(matchingRows[0]?.current_ingestion_key),
    },
    binary: sourceItem.binary,
  });
}

return changedItems;
